var SCR_W=800;var SCR_H=900;var STEP=50;var WAIT=12;var PAUSE=500;var MX=parseInt(SCR_W/2);var MY=parseInt(SCR_H/2);var R_STAGE=0;var S_INIT=0;var S_CENTER=1;var S_TL=2;var S_TR=3;var S_BR=4;var S_BL=5;if(ble_check()){var stage=rread(R_STAGE);switch(stage){default:case S_INIT:print("INIT: reset to top-left corner");rwrite(R_STAGE,S_CENTER);mouse_move_to(-1e4,-1e4);delay(300);break;case S_CENTER:print("MOVE: to center");rwrite(R_STAGE,S_TL);mouse_move_to(SCR_W,SCR_H,STEP,WAIT);delay(PAUSE);break;case S_TL:print("MOVE: center -> top-left mid -> center");rwrite(R_STAGE,S_TR);mouse_move_to(-MX,-MY,STEP,WAIT);delay(PAUSE);mouse_move_to(MX,MY,STEP,WAIT);delay(PAUSE);break;case S_TR:print("MOVE: center -> top-right mid -> center");rwrite(R_STAGE,S_BR);mouse_move_to(MX,-MY,STEP,WAIT);delay(PAUSE);mouse_move_to(-MX,MY,STEP,WAIT);delay(PAUSE);break;case S_BR:print("MOVE: center -> bottom-right mid -> center");rwrite(R_STAGE,S_BL);mouse_move_to(MX,MY,STEP,WAIT);delay(PAUSE);mouse_move_to(-MX,-MY,STEP,WAIT);delay(PAUSE);break;case S_BL:print("MOVE: center -> bottom-left mid -> center");rwrite(R_STAGE,S_TL);mouse_move_to(-MX,MY,STEP,WAIT);delay(PAUSE);mouse_move_to(MX,-MY,STEP,WAIT);delay(PAUSE);break}}else{print("BLE not connected, waiting...");delay(1e3)}